function inputActionMacthesTargetNotRepeating(
  targetGeId: GameEventId,
  ia: InputAction,
  prevIa: InputAction | undefined
) {
  if (ia.Action !== targetGeId) {
    return false;
  }
  if (prevIa === undefined) {
    return true;
  }
  if (ia.Action === prevIa.Action) {
    return false;
  }
  return true;
}

function isBufferedInput(
  inputStore: IInputStore,
  currentFrame: number,
  bufferFrames: number,
  targetGameEvent: GameEventId
): boolean {
  for (let i = 0; i < bufferFrames; i++) {
    const ia = inputStore.GetInputForFrame(currentFrame - i);
    if (!ia) continue;
    if (ia.Action === targetGameEvent) {
      // Check if the input was held for more than the buffer window
      const prevIa = inputStore.GetInputForFrame(currentFrame - i - 1);
      if (prevIa.Action !== targetGameEvent) {
        return true;
      }
    }
  }
  return false;
}

export const LedgeGrabToGetUp: condition = {
  Name: 'LedgeGrabToGetUp',
  ConditionFunc: (w: World, p: Player, ia: InputAction) => {
    // Jump button
    // Up on the left stick
    if (ia.LYAxis.Raw > NumberToRaw(0.25)) {
      return true;
    }
    // Push towards stage on left stick
    if (p.Flags.IsFacingRight && ia.LXAxis.Raw > NumberToRaw(0.25)) {
      return true;
    }
    if (p.Flags.IsFacingLeft && ia.LXAxis.Raw < NumberToRaw(-0.25)) {
      return true;
    }
    return false;
  },
  StateId: STATE_IDS.LEDGE_GETUP_S
};

